154→// ═══ 声音 ═══
155→let audioCtx=null,soundOn=true;
156→function initAudio(){if(!audioCtx)audioCtx=new(window.AudioContext||window.webkitAudioContext)()}
157→function toggleSound(){soundOn=!soundOn;document.getElementById('soundBtn').textContent=soundOn?'🔊 声音开':'🔇 声音关'}
158→function playTick(){if(!soundOn)return;initAudio();const o=audioCtx.createOscillator(),g=audioCtx.createGain();o.connect(g);g.connect(audioCtx.destination);o.frequency.value=660+Math.random()*80;o.type='sine';g.gain.setValueAtTime(.05,audioCtx.currentTime);g.gain.exponentialRampToValueAtTime(.001,audioCtx.currentTime+.07);o.start();o.stop(audioCtx.currentTime+.07)}
159→function playReveal(){if(!soundOn)return;initAudio();[523,659,784].forEach((f,i)=>{const o=audioCtx.createOscillator(),g=audioCtx.createGain();o.connect(g);g.connect(audioCtx.destination);o.frequency.value=f;o.type='sine';const t=audioCtx.currentTime+i*.06;g.gain.setValueAtTime(.04,t);g.gain.exponentialRampToValueAtTime(.001,t+.18);o.start(t);o.stop(t+.18)})}
160→function playCliff(){if(!soundOn)return;initAudio();const o=audioCtx.createOscillator(),g=audioCtx.createGain();o.connect(g);g.connect(audioCtx.destination);o.frequency.setValueAtTime(800,audioCtx.currentTime);o.frequency.exponentialRampToValueAtTime(200,audioCtx.currentTime+.4);o.type='sine';g.gain.setValueAtTime(.06,audioCtx.currentTime);g.gain.exponentialRampToValueAtTime(.001,audioCtx.currentTime+.4);o.start();o.stop(audioCtx.currentTime+.4)}
161→
162→// ═══ 交互 1: 需求曲线断崖探测器 ═══
163→// Pre-generated survey: 200 people's "too expensive" thresholds
164→// Distribution shaped to create a visible cliff around $33-38
165→const SURVEY_DATA=(function(){
166→  const data=[];
167→  // Build a realistic distribution: cluster around $25-35 with a cliff at $35-40
168→  // "Would still buy at this price" cumulative curve
169→  function addGroup(n,min,max){for(let i=0;i<n;i++)data.push(min+Math.random()*(max-min))}
170→  addGroup(12,10,18);   // very price sensitive
171→  addGroup(25,18,25);   // budget conscious
172→  addGroup(45,25,32);   // mainstream sweet spot
173→  addGroup(55,32,38);   // still willing but stretching
174→  addGroup(30,38,42);   // cliff zone: drops fast
175→  addGroup(15,42,48);   // only committed buyers
176→  addGroup(10,48,55);   // enthusiasts
177→  addGroup(5,55,65);    // die-hards
178→  addGroup(3,65,80);    // will pay anything
179→  return data.sort((a,b)=>a-b);
180→})();
181→
182→function getWillingPct(price){
183→  return SURVEY_DATA.filter(d=>d>=price).length/SURVEY_DATA.length*100;
184→}
185→
186→function renderCliff(){
187→  const canvas=document.getElementById('cliffCanvas');
188→  const ctx=canvas.getContext('2d');
189→  const W=canvas.width,H=canvas.height;
190→  const padL=50,padR=20,padT=20,padB=40;
191→  const gW=W-padL-padR, gH=H-padT-padB;
192→
193→  const price=+document.getElementById('cliffSlider').value;
194→  document.getElementById('cliffPrice').textContent='$'+price;
195→
196→  ctx.clearRect(0,0,W,H);
197→
198→  // Background
199→  ctx.fillStyle='#faf9f6';
200→  ctx.fillRect(padL,padT,gW,gH);
201→
202→  // Grid lines
203→  ctx.strokeStyle='#e4e0d8';
204→  ctx.lineWidth=0.5;
205→  for(let p=0;p<=100;p+=25){
206→    const y=padT+gH-(p/100*gH);
207→    ctx.beginPath();ctx.moveTo(padL,y);ctx.lineTo(padL+gW,y);ctx.stroke();
208→    ctx.fillStyle='#999';ctx.font='10px Menlo,Consolas,monospace';ctx.textAlign='right';
209→    ctx.fillText(p+'%',padL-6,y+3);
210→  }
211→  // X axis labels
212→  ctx.textAlign='center';
213→  for(let d=10;d<=80;d+=10){
214→    const x=padL+(d-5)/75*gW;
215→    ctx.fillStyle='#999';ctx.fillText('$'+d,x,H-8);
216→  }
217→  ctx.fillStyle='#999';ctx.font='10px Menlo,Consolas,monospace';
218→  ctx.fillText('愿意购买的用户比例 (%)',padL+gW/2,padT-6);
219→
220→  // Compute demand curve points
221→  const points=[];
222→  for(let p=5;p<=80;p+=0.5){
223→    const pct=getWillingPct(p);
224→    const x=padL+(p-5)/75*gW;
225→    const y=padT+gH-(pct/100*gH);
226→    points.push({price:p,pct,x,y});
227→  }
228→
229→  // Fill area under curve up to current price
230→  ctx.beginPath();
231→  ctx.moveTo(points[0].x,padT+gH);
232→  points.forEach(pt=>{
233→    if(pt.price<=price)ctx.lineTo(pt.x,pt.y);
234→  });
235→  const curPt=points.find(pt=>pt.price>=price)||points[points.length-1];
236→  ctx.lineTo(curPt.x,padT+gH);
237→  ctx.closePath();
238→  ctx.fillStyle='rgba(74,143,92,0.12)';
239→  ctx.fill();
240→
241→  // Draw demand curve
242→  ctx.beginPath();
243→  ctx.moveTo(points[0].x,points[0].y);
244→  points.forEach(pt=>ctx.lineTo(pt.x,pt.y));
245→  ctx.strokeStyle='#1a1a1a';
246→  ctx.lineWidth=2.5;
247→  ctx.stroke();
248→
249→  // Highlight cliff zone (where derivative is steepest)
250→  // Find steepest drop
251→  let maxDrop=0, cliffPrice=35;
252→  for(let i=1;i<points.length;i++){
253→    const drop=points[i-1].pct-points[i].pct;
254→    if(drop>maxDrop){maxDrop=drop;cliffPrice=points[i].price}
255→  }
256→  // Draw cliff zone band
257→  const cliffStart=Math.max(5,cliffPrice-5), cliffEnd=Math.min(80,cliffPrice+5);
258→  const cx1=padL+(cliffStart-5)/75*gW, cx2=padL+(cliffEnd-5)/75*gW;
259→  ctx.fillStyle='rgba(184,76,76,0.08)';
260→  ctx.fillRect(cx1,padT,cx2-cx1,gH);
261→  // Cliff label
262→  ctx.fillStyle='#b84c4c';ctx.font='bold 10px Menlo,Consolas,monospace';ctx.textAlign='center';
263→  ctx.fillText('⚠ 悬崖区',((cx1+cx2)/2),padT+12);
264→
265→  // Price line (vertical)
266→  const px=padL+(price-5)/75*gW;
267→  ctx.beginPath();ctx.moveTo(px,padT);ctx.lineTo(px,padT+gH);
268→  ctx.strokeStyle='#c07b20';ctx.lineWidth=2;ctx.setLineDash([6,4]);ctx.stroke();ctx.setLineDash([]);
269→
270→  // Current point on curve
271→  const curPct=getWillingPct(price);
272→  const curY=padT+gH-(curPct/100*gH);
273→  ctx.beginPath();ctx.arc(px,curY,6,0,Math.PI*2);ctx.fillStyle='#c07b20';ctx.fill();
274→  ctx.beginPath();ctx.arc(px,curY,6,0,Math.PI*2);ctx.strokeStyle='#fff';ctx.lineWidth=2;ctx.stroke();
